+  const containerRef = React.useRef<HTMLDivElement>(null);
+
+  const heightRef = React.useRef<number | null>(null);
+
+  React.useEffect(() => {
+    const container = containerRef.current;
+    if (!container) return;
+    const height = container.offsetHeight;
